mapper.select:
select id, admin_id as adminId, username, operation_module as operationModule, operation_type as operationType, operation_desc as operationDesc, request_method as requestMethod, request_path as requestPath, request_ip as requestIp, user_agent as userAgent, operation_status as operationStatus, error_message as errorMessage, operation_time as operationTime from admin_operation_log
and admin_id = #{query.adminId}
and username like concat('%', #{query.username}, '%')
and operation_module = #{query.operationModule}
and operation_type = #{query.operationType}
and operation_status = #{query.operationStatus}
and operation_time >= #{query.startTime}
and operation_time <= #{query.endTime}
order by operation_time desc, id desc
